import Vue from 'vue'
import VueRouter from 'vue-router'
import Gurugu from '../views/Gurugu.vue'
import { auth } from '../firebase'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: '/Gurugu',
    component: Gurugu,
    meta: { title: 'Sala Gurugú'}
    // meta: { requiresAuth: true }
  },
  {
    path: '/espacio',
    name: 'Espacio',
    component: () => import('../views/Espacio.vue')
  },
  {
    path: '/danthea',
    name: 'Danthea',
    component: () => import('../views/Danthea.vue')
  },
  {
    path: '/talleres',
    name: 'Talleres',
    component: () => import('../views/Talleres.vue')
  },
  {
    path: '/exempla',
    name: 'Exempla',
    component: () => import('../views/Exempla.vue')
  },
  {
    path: '/localizacion',
    name: 'Localizacion',
    component: () => import('../views/Localizacion.vue')
  },
  {
    path: '/contacto',
    name: 'Contacto',
    component: () => import('../views/Contacto.vue')
  },
  {
    path: '/login',
    name: 'Login',
    component: () => import('../views/Login.vue')
  },
  {
    path: '/registro',
    name: 'Registro',
    component: () => import('../views/Registro.vue')
  },
  {
    path: '/form',
    name: 'form',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/Form.vue')
  },
  {
    path: '/obra/:id',
    name: 'Obra',
    component: () => import('../views/Obra.vue')
  },
  {
    path: '/storage',
    name: 'Storage',
    component: () => import('../views/Storage.vue')
  }
]

const router = new VueRouter({
  routes
})

router.beforeEach((to, from, next) => {
  if (to.matched.some(record => record.meta.requiresAuth)) {

    const usuario = auth.currentUser
    console.log(usuario)

    if (!usuario) {
      next({
        path: '/login'
      })
    } else {
      next()
    }

  } else {
    next()
  }
})

export default router
